    {
    }

    double getX() const { return m_x; }
    double getY() const { return m_y; }
    double getZ() const { return m_z; }

    void print() const
    {
        std::cout << "Point(" << m_x << ", " << m_y << ", " << m_z << ')';
    }
};While this is much better, it still has some downsides. Becauseprint()returnsvoid, it can’t be called in the middle of an output statement. Instead, you have to do this:int main()
